// -- packages/opencode/src/tool/errors.ts --
import { Schema } from "effect"

// Base tagged error for ALL recoverable tool errors
export class ToolError extends Schema.TaggedErrorClass<ToolError>()("ToolError", {
  tool: Schema.String,
  detail: Schema.String,
  recoverable: Schema.Boolean,
}) {
  get message(): string {
    const hint = this.recoverable
      ? " Please correct the input and retry."
      : " This cannot be recovered by retrying."
    return `[${this.tool}] ${this.detail}.${hint}`
  }
}

// Specific subtypes for network tools
export class NetworkError extends Schema.TaggedErrorClass<NetworkError>()("NetworkError", {
  tool: Schema.String,
  detail: Schema.String,
  statusCode: Schema.optional(Schema.Number),
}) {
  override get message(): string {
    const code = this.statusCode ? ` (HTTP ${this.statusCode})` : ""
    return `[${this.tool}] Network request failed${code}: ${this.detail}. The tool will retry automatically.`
  }
}

export class TimeoutError extends Schema.TaggedErrorClass<TimeoutError>()("TimeoutError", {
  tool: Schema.String,
  detail: Schema.String,
  durationMs: Schema.Number,
}) {
  override get message(): string {
    return `[${this.tool}] Timed out after ${this.durationMs}ms: ${this.detail}. Consider a larger timeout or a simpler operation.`
  }
}

export class PermissionDeniedError extends Schema.TaggedErrorClass<PermissionDeniedError>()("PermissionDeniedError", {
  tool: Schema.String,
  detail: Schema.String,
  resource: Schema.String,
}) {
  override get message(): string {
    return `[${this.tool}] Permission denied for resource "${this.resource}": ${this.detail}.`
  }
}

// -- In session/tools.ts, the catch boundary becomes:
yield* Effect.catchAll(error => {
  if (error instanceof ToolError) {
    yield* Execution.publishFailed(bus, ctx.sessionID, callID, tool.id, error.message)
    return { title: tool.id, metadata: { error: true }, output: error.message }
  }
  // Unknown errors still orDie (programming errors)
  return yield* Effect.die(error)
})

// Inside a network tool's execute method:
return Effect.gen(function* () {
  const result = yield* httpRequest(params).pipe(
    Effect.retry({
      while: (error) => error instanceof NetworkError && error.statusCode !== 403 && error.statusCode !== 404,
      schedule: Schedule.exponential("500 millis").pipe(
        Schedule.either(Schedule.recurs(3)),
        Schedule.union(Schedule.maxDelay("10 seconds")),
      ),
    }),
    Effect.timeout("25 seconds"),
  )
  return formatResult(result)
}).pipe(
  Effect.catchSome((error) => {
    if (error instanceof TimeoutError) return Effect.succeed({
      title: 'fetch',
      metadata: { status: 'timeout' },
      output: `Request timed out after 25s. Try a simpler URL or check network.`
    })
    return Effect.fail(error) // let the bridge handle other ToolErrors
  }),
)

// In tool.ts wrap() — already present but should be mandatory:
const decoded = yield* decode(args).pipe(
  Effect.mapError((error) =>
    new InvalidArgumentsError({
      tool: id,
      detail: toolInfo.formatValidationError
        ? toolInfo.formatValidationError(error)
        : String(error),
    }),
  ),
)

// Every tool MUST provide formatValidationError — example:
formatValidationError: (error) => {
  if (ParseResult.isParseError(error)) {
    const issues = ParseResult.getErrors(error).map(e =>
      `- ${e.path.join('.')}: ${e.message}`
    ).join('\n')
    return `Validation failed:\n${issues}\n\nExpected schema:\n${JSON.stringify(Parameters.ast, null, 2)}`
  }
  return String(error)
}

// In each tool's execute method — the outermost pipe:
execute: (params, ctx) =>
  Effect.gen(function* () {
    // ... happy path logic
  }).pipe(
    Effect.timeout({
      duration: toolSpecificTimeout,   // e.g. 120_000 for shell, 10_000 for grep
      onTimeout: () => new TimeoutError({ tool: id, detail: 'execution timed out', durationMs: toolSpecificTimeout }),
    }),
    Effect.catchTag('TimeoutError', (err) => Effect.succeed({
      title: id,
      metadata: { timedOut: true, durationMs: err.durationMs },
      output: `[${id}] Timed out after ${err.durationMs}ms. ${getRecoveryHint(id)}`,
    })),
  )

// -- packages/opencode/src/tool/circuit-breaker.ts --
import { CircuitBreaker as CB } from "effect"

export class ToolCircuitBreaker extends Context.Service<ToolCircuitBreaker>()("@opencode/ToolCircuitBreaker", {
  // CircuitBreaker factory from effect
  ref: CB.CircuitBreaker<unknown, unknown>,
}) {}

// In tool definition:
const cb = yield* ToolCircuitBreaker
return {
  execute: (params, ctx) => cb.ref.pipe(
    CB.withCircuitBreaker(
      Effect.gen(function* () {
        // actual shell/spawn logic
      }),
    ),
  ),
}

// Default config: maxFailures=5, resetPeriod='30 seconds'
// This prevents repeated failures from flooding the semaphore pool

// Every helper defined with Effect.fn() gets auto-spanning:
const resolvePath = Effect.fn("ReadTool.resolvePath")(function* (file: string) {
  // This function creates a span at "ReadTool.resolvePath" automatically
  const instance = yield* InstanceState.context
  return path.isAbsolute(file) ? file : path.join(instance.directory, file)
})

// For side-effect operations, annotate spans explicitly:
const result = yield* fs.readFileString(filePath).pipe(
  Effect.withSpan("ReadTool.readFile", {
    attributes: { "file.path": filePath, "file.size": fileSize },
  }),
)

// When forking, use forkScoped to maintain span parent-child:
yield* Effect.forkScoped(    // NOT Effect.fork — forkScoped maintains trace
  processLargeResult(stream).pipe(
    Effect.withSpan("ShellTool.processStream"),
  ),
)

// In session/tools.ts, wrap the entire semaphore.withPermit with a root span:
semaphore.withPermit(
  Effect.gen(function* () {
    // ... tool execution
  }).pipe(
    Effect.withSpan("Tool.execute", {
      attributes: {
        "tool.name": item.id,
        "session.id": ctx.sessionID,
        "message.id": ctx.messageID,
        "tool.call_id": ctx.callID,
        "tool.cacheable": item.cacheable,
        "semaphore.permits_used": 1,
      },
    }),
  ),
)

// Top of every tool file:
import * as Log from "@opencode-ai/core/util/log"
const log = Log.create({ service: "tool.<name>" })    // e.g., "tool.grep", "tool.shell"

// Inside execute:
log.info("tool execution started", {
  params: { pattern: params.pattern, path: params.path },
  callID: ctx.callID,
})

// Inside cache check:
log.debug("cache lookup", { cacheable: true, key: cacheKey, hit: Boolean(cached) })

// On error (before typed error is returned):
log.error("network request failed", {
  url,
  statusCode: error.statusCode,
  durationMs: Date.now() - start,
})

// NEVER:
log.info(`Started tool ${id} with params ${JSON.stringify(params)}`)

// Heartbeat pattern for long-running tools:
const heartbeat = yield* Effect.forever(
  Effect.sleep("2 seconds").pipe(
    Effect.andThen(() => ctx.metadata({
      metadata: {
        status: "running",
        progress: { bytesDownloaded, totalBytes, elapsedMs },
      },
    })),
  ),
)
yield* Effect.forkScoped(heartbeat)

// When done, the fiber is auto-interrupted by the scope
// This keeps the UI updated without blocking execution

// Canonical ExecuteResult shape:
{
  title: `${tool.id}: one-line summary for UI`,   // e.g., "grep: findUser"
  metadata: {
    status: 'success',       // canonical status — one of: success, fail, timeout, partial, error
    toolCallId: ctx.callID,  // for correlation
    // Tool-specific structured metadata:
    matches: 42,
    truncated: false,
    // Execution metadata (not result metadata) is annotated by the wrapper:
    // cacheHit, durationMs, outputSizeBytes come from the bridge, not the tool
  },
  output: `Found 42 matches:\n\n/path/to/file.ts:\n  Line 12: const user = findUser(id)\n...`,  // LLM-facing formatted text
}

// Error result:
{
  title: 'smart_edit',
  metadata: { status: 'fail', file: '/path/to/file.ts', reason: 'not_found' },
  output: JSON.stringify({
    status: 'fail',
    error: 'oldText not found in file',
    hint: 'Check exact whitespace and line endings. The file currently starts with: "import { ... }"',
  }, null, 2),
}

// Good:
`File not found: ${filePath}. Check that the path exists and is readable.`

// Also good:
`Pattern "${pattern}" is not a valid regex: ${error.message}. Try escaping special characters or using a simpler pattern.`

// Bad — no actionable guidance:
`Invalid pattern`

// Canonical format for formatValidationError:
`The ${this.tool} tool was called with invalid arguments for field "${fieldPath}": expected ${expected}, got ${got}.\nPlease rewrite the input so ${fieldPath} satisfies ${description}.\n\nFull schema:\n${JSON.stringify(schema, null, 2)}`

// Good — init is pure:
export const GrepTool = Tool.define(
  'grep',
  Effect.gen(function* () {
    const fs = yield* AppFileSystem.Service
    const rg = yield* Ripgrep.Service
    return {
      description: DESCRIPTION,
      parameters: Parameters,
      cacheable: true,
      execute: (params, ctx) =>
        Effect.gen(function* () {
          // All side effects happen here
          const result = yield* rg.search({ ... })
          return { title, metadata, output }
        }),
    }
  }),
)

// Also good — lazy WASM loading:
const parser = lazy(async () => {
  // This runs on first parse() call, not at init time
  const { Parser } = await import('web-tree-sitter')
  // ...
  return { bash, ps }
})

// In session/tools.ts:
const readSemaphore = yield* Semaphore.make(5)
const writeSemaphore = yield* Semaphore.make(2)

// In tool resolution:
const semaphore = isWriteTool(item.id) ? writeSemaphore : readSemaphore

tools[item.id] = tool({
  execute: (args, options) =>
    run.promise(
      semaphore.withPermit(
        Effect.gen(function* () {
          // ...
        }).pipe(
          Effect.withSpan("Tool.execute", ...)
        ),
      ),
    ),
})

// Helper:
const WRITE_TOOLS = new Set(['edit', 'write', 'smart_edit', 'shell', 'smart_batch', 'search_replace', 'checkpoint', 'apply_patch', 'prepare_checkpoint'])
function isWriteTool(id: string): boolean {
  return WRITE_TOOLS.has(id)
}

// Extend Tool.Def:
export interface Def<..., R = any> {
  // ... existing fields
  cacheable?: boolean
  maxConcurrency?: number     // NEW — max concurrent executions per tool
  isWrite?: boolean            // NEW — uses write semaphore
  timeoutMs?: number           // NEW — tool-specific timeout
}

// In session/tools.ts:
const perToolSemaphores = new Map<string, Semaphore>()

function getToolSemaphore(id: string, maxConcurrency?: number): Semaphore {
  if (!maxConcurrency) return isWriteTool(id) ? writeSemaphore : readSemaphore
  let sem = perToolSemaphores.get(id)
  if (!sem) {
    sem = Semaphore.make(maxConcurrency)
    perToolSemaphores.set(id, sem)
  }
  return sem
}

// Then:
const toolSemaphore = getToolSemaphore(item.id, item.maxConcurrency)
// Acquire BOTH the global semaphore (for fairness) AND the per-tool semaphore
// Better: just use per-tool semaphore when specified, else fall back to global

// Good — already the pattern:
// In registry.ts defaultLayer:
Layer.provide(FetchHttpClient.layer)   // shared HTTP client with connection pooling
Layer.provide(DatabaseAdapter.defaultLayer)  // shared DB adapter

// Tool acquires shared service:
const http = yield* HttpClient.HttpClient  // same client reused across tools

// If a tool needs an exclusive connection:
const db = yield* DatabaseAdapter.Service
const exclusive = yield* db.checkout()  // acquire from pool
// ... use exclusive connection ...
yield* Scope.close()  // return to pool

// Inside a batch tool:
const results = yield* Effect.forEach(
  params.edits,
  (edit) =>
    Effect.gen(function* () {
      // apply single edit
      return yield* applyOne(edit, ctx)
    }).pipe(
      Effect.withSpan("BatchEdit.apply", {
        attributes: { "edit.file": edit.file },
      }),
    ),
  { concurrency: 4 },   // small bounded concurrency — not "unbounded"
)

// For file reads (grep, read tool):
const stats = yield* Effect.forEach(
  files,
  (file) => fs.stat(file).pipe(Effect.catch(() => Effect.succeed(undefined))),
  { concurrency: 16 },  // file system handles this well
)

// Canonical scoped subprocess pattern:
const result = yield* Effect.scoped(
  Effect.gen(function* () {
    const proc = yield* spawner.spawn(cmd)

    // Auto-cleanup when scope closes (abort, timeout, completion):
    yield* Effect.addFinalizer(() =>
      Effect.orDie(proc.kill({ forceKillAfter: "3 seconds" }))
    )

    const output = yield* collectOutput(proc)
    return output
  }),
)

// Canonical scoped resource pattern:
yield* Effect.acquireRelease(
  openResource(),      // acquire
  (resource) => closeResource(resource),  // release
).pipe(
  Effect.flatMap((resource) => useResource(resource)),
)

// -- packages/opencode/src/tool/stripe-lock.ts --
import { Effect, HashMap, Ref, Semaphore } from "effect"

export class StripeLock extends Context.Service<StripeLock>()("@opencode/StripeLock", {
  ref: Ref.Ref<HashMap.HashMap<string, Semaphore>>,
}) {}

export const getLock = Effect.fn("StripeLock.getLock")(function* (key: string) {
  const service = yield* StripeLock
  let sem = yield* Ref.get(service.ref).pipe(
    Effect.map((map) => HashMap.get(map, key)),
  )
  if (sem._tag === "None") {
    const newSem = yield* Semaphore.make(1)
    yield* Ref.update(service.ref, (map) => HashMap.set(map, key, newSem))
    sem = { _tag: "Some", value: newSem }
  }
  return sem.value
})

// Usage in smart_edit:
const lock = yield* getLock(params.file)
return lock.withPermit(
  Effect.gen(function* () {
    return yield* applyEdit(params)
  }),
)

// Good — shell tool streams output through a sliding window:
const keep = limits.maxBytes * 2
let full = ''
const list: Chunk[] = []
let used = 0
let file = ''

yield* Effect.forkScoped(
  Stream.runForEach(Stream.decodeText(handle.all), (chunk) => {
    list.push({ text: chunk, size })
    used += size
    while (used > keep && list.length > 1) {
      const item = list.shift()
      used -= item.size
    }
    // spill to disk if over budget
    if (Buffer.byteLength(full) > limits.maxBytes) {
      return trunc.write(full).pipe(
        Effect.andThen((path) => { file = path; full = '' }),
      )
    }
    return Effect.void
  }),
)

// For large file reads — use streaming:
export function readLargeFile(filePath: string, maxBytes: number) {
  return Stream.fromReadable(() => createReadStream(filePath)).pipe(
    Stream.takeWhile((_) => /* byte budget remaining */),
    Stream.runCollect,
    Effect.map((chunks) => Buffer.concat([...chunks]).toString('utf-8')),
  )
}

// Enhanced ToolCache:
interface CacheConfig {
  maxEntries: number     // default 100
  ttlMs: number          // default 300000 (5 min)
}

const getOrCompute = (key, compute) =>
  Effect.gen(function* () {
    const map = yield* Ref.get(cache)
    const entry = map[key]
    if (entry && (Date.now() - entry.storedAt) < config.ttlMs) {
      return entry.result
    }
    // ... compute and store ...
    yield* evictIfNeeded()
  })

const evictIfNeeded = Effect.fn("Cache.evictIfNeeded")(function* () {
  const map = yield* Ref.get(cache)
  const keys = Object.keys(map)
  if (keys.length <= config.maxEntries) return
  // Evict oldest entries
  const sorted = keys.sort((a, b) => map[a].storedAt - map[b].storedAt)
  const toRemove = sorted.slice(0, keys.length - config.maxEntries)
  yield* Ref.update(cache, (m) => {
    const next = { ...m }
    for (const key of toRemove) delete next[key]
    return next
  })
})

// Define tool-specific transient resources:
export const MyToolLive = Layer.scoped(
  MyTool,
  Effect.gen(function* () {
    const conn = yield* openPooledConnection()  // acquired once per tool lifecycle
    yield* Effect.addFinalizer(() => closeConnection(conn))
    return MyTool.of({ conn })
  }),
)

// Or for per-execution resources:
execute: (params, ctx) =>
  Effect.scoped(
    Effect.gen(function* () {
      const tempDir = yield* makeTempDir()
      yield* Effect.addFinalizer(() => removeTempDir(tempDir))
      return yield* doWork(tempDir, params)
    }),
  )

// Good — lazy parser init (from shell.ts):
const parser = lazy(async () => {
  // This runs on first parse() call, not at Tool.define time
  const { Parser } = await import('web-tree-sitter')
  // ... heavy WASM loading ...
  return { bash, ps }
})

// Good — schema is compiled at module load (fast):
const Parameters = Schema.Struct({
  pattern: Schema.String,
})

// Bad — waiting in init:
export const HeavyTool = Tool.define(
  'heavy',
  Effect.gen(function* () {
    const language = yield* Effect.promise(() => loadHeavyWasm())  // Blocks init
    return {
      execute: (params, ctx) => useLanguage(language),
    }
  }),
)

// Good — deferred to execute:
export const HeavyTool = Tool.define(
  'heavy',
  Effect.gen(function* () {
    const lazyLanguage = lazy(() => loadHeavyWasm())
    return {
      execute: (params, ctx) =>
        Effect.gen(function* () {
          const language = yield* Effect.promise(() => lazyLanguage())
          return useLanguage(language)
        }),
    }
  }),
)

// Cache entry now includes tags:
interface CacheEntry {
  result: any
  storedAt: number
  tags: string[]   // e.g., ['file:/path/to/foo.ts', 'glob:*.ts']
}

// Write tools publish affected tags:
const invalidateTags = writeToolTags(params)  // ['file:/path/to/foo.ts']

yield* cache.invalidateTags(invalidateTags)

// Cache invalidation:
const invalidateTags: Interface['invalidateTags'] = (tags) =>
  Ref.update(cache, (m) => {
    const next = { ...m }
    for (const key of Object.keys(next)) {
      if (next[key].tags.some((t) => tags.includes(t))) {
        delete next[key]
      }
    }
    return next
  })

// Good — shell tool re-reads config on every execute:
return () =>
  Effect.gen(function* () {
    const cfg = yield* config.get()  // re-reads on each init call
    const shell = Shell.acceptable(cfg.shell)
    return {
      description: prompt.description,
      parameters: prompt.parameters,
      execute: ...,
    }
  })

// Bad — config read once at tool registration:
export const BadTool = Tool.define(
  'bad',
  Effect.gen(function* () {
    const cfg = yield* config.get()  // captured once, never updates
    return {
      description: `Current timeout: ${cfg.timeout}`,  // stale if config changes
      execute: ...
    }
  }),
)

