// packages/opencode/src/tool/<name>.ts
import { Effect, Schema } from "effect"
import * as Tool from "./tool"
import * as Log from "@opencode-ai/core/util/log"
import DESCRIPTION from "./<name>.txt"

// ---- 1. Parameters Schema (one declaration, exported for testing) ----
export const Parameters = Schema.Struct({
  input: Schema.String.annotate({ description: "Primary input parameter" }),
  option: Schema.optional(Schema.Number).annotate({
    description: "Optional numeric parameter",
  }),
})

// ---- 2. Module-level logger ----
const log = Log.create({ service: "tool.<name>" })

// ---- 3. Tool definition (pure init, deferred heavy resources) ----
export const MyTool = Tool.define(
  "<name>",
  Effect.gen(function* () {
    // Acquire session-level services here (HTTP, FS, DB)
    const fs = yield* AppFileSystem.Service

    // Defer heavy resources with lazy()
    // const heavy = lazy(() => loadHeavyWasm())

    return {
      description: DESCRIPTION,
      parameters: Parameters,
      cacheable: false,              // Set to true if read-only & deterministic
      maxConcurrency: 2,             // Set appropriate limit
      timeoutMs: 10_000,             // Tool-specific timeout

      // ---- 4. LLM-actionable validation error ----
      formatValidationError: (error) => {
        if (ParseResult.isParseError(error)) {
          return `Invalid <name> arguments: ${ParseResult.getErrors(error)
            .map(e => `- ${e.path.join('.')}: ${e.message}`)
            .join('\n')}\nExpected schema: ${JSON.stringify(Parameters.ast, null, 2)}`
        }
        return String(error)
      },

      // ---- 5. Execute — all side effects here ----
      execute: (params: Schema.Schema.Type<typeof Parameters>, ctx: Tool.Context) =>
        Effect.gen(function* () {
          log.info("execution started", {
            input: params.input,
            callID: ctx.callID,
          })

          // Validate business rules (NOT schema — schema is already validated)
          if (params.input.length === 0) {
            return {
              title: "<name>",
              metadata: { status: "fail" },
              output: `[<name>] Input cannot be empty. Provide at least one character.`,
            }
          }

          // ---- 6. Core logic ----
          const result = yield* doWork(params, fs).pipe(
            // Effect.withSpan("MyTool.doWork", { attributes: { ... } }),
          )

          return {
            title: `<name>: ${params.input.slice(0, 50)}`,
            metadata: { status: "success", key: result.key },
            output: formatResult(result),
          }
        }).pipe(
          // ---- 7. Reliability wrappers ----
          Effect.timeout({
            duration: "10 seconds",
            onTimeout: () => new ToolError({
              tool: "<name>",
              detail: "execution timed out",
              recoverable: true,
            }),
          }),
          Effect.catchTag("ToolError", (error) =>
            Effect.succeed({
              title: "<name>",
              metadata: { status: "error" },
              output: error.message,
            }),
          ),
          Effect.orDie,  // still die on unexpected errors
        ),
    }
  }),
)

export * as MyTool from "./<name>"
